export default {
  data() {
    return {
      snc_visible: false,
      desiredName: "",
      verifyName: "",
      snc_res_color: "",
      snc_response: "",
      snc_available: false,
      snc_item: {
        price: 420
      }
    };
  },
  beforeMount() {
    this.$store.dispatch("changeBackgroundState", "HOME");
  },
  computed: {
    canBuyNameChange() {
      return this.verifyName == this.desiredName && this.desiredName != "" && this.snc_available == true;
    }
  },
  methods: {
    openSncModal(item) {
      this.$sound.template("OVERVIEW_CLICK");
      this.snc_item = item;
      this.snc_visible = true;
    },
    buyNameChange() {
      if (this.canBuyNameChange) {
        this.$store.dispatch("postPurchaseItem", {
          item: this.snc_item,
          category: "Account",
          desiredName: this.desiredName
        }).then(response => {
          if (response.status === 200) {
            this.$sound.template("CORE_SHOP_BUY_GENERAL");
            this.$store.dispatch("getStoreItems", "account").then(items => {
              this.items = items;
            });
            this.$store.dispatch("deductUserCoins", this.snc_item.price);
          }
        });
      }
    },
    sncCheck() {
      if (this.desiredName.match(/^[a-zA-Z0-9]*$/) != null && this.desiredName.length <= 12 && this.desiredName.length >= 3) {
        this.$store.dispatch("getStoreCheckName", this.desiredName).then(isAvailable => {
          if (!isAvailable) {
            this.snc_response = this.$translate.text("SNCMDL_CHECK_RESPONSE_INUSE");
            this.snc_res_color = "red";
            this.snc_available = false;
          } else {
            this.snc_res_color = "green";
            this.snc_response = this.$translate.text("SNCMDL_CHECK_RESPONSE_AVAILABLE");
            this.snc_available = true;
          }
        });
      } else {
        this.snc_res_color = "red";
        this.snc_response = this.$translate.text("SNCMDL_CHECK_RESPONSE_INVALID");
        this.snc_available = false;
      }
    },
    clickSound() {
      this.$sound.template("OVERVIEW_CLICK");
    }
  }
};
